import React from 'react'
import {Switch, Route} from 'react-router-dom'

// Project list
import ProjectList from './ProjectsList'
// Projects
import ProjectSBMS from './pages/SmartBrakeMonitoringSystem'

class ProjectRouter extends React.Component {

  render() {
    return (<div>

        <Switch>

          {/* First level */}
          <Route path='/projects/smart-brake-monitoring-system'>
            <ProjectSBMS/>
          </Route>
          {/* Root */}
          <Route path='/projects'>
            <ProjectList/>
          </Route>

        </Switch>

    </div>)
  }

}

export default ProjectRouter
